DROP TABLE IF EXISTS `indicator_campaign`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `indicator_campaign` (
  `indicator_id` int NOT NULL,
  `campaign_id` int NOT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`indicator_id`,`campaign_id`),
  KEY `idx_campaign` (`campaign_id`),
  CONSTRAINT `indicator_campaign_ibfk_1` FOREIGN KEY (`indicator_id`) REFERENCES `indicators` (`indicator_id`) ON DELETE CASCADE,
